import { Legend } from "chart.js";
import React from "react";
import { Bar } from 'react-chartjs-2';
import { COLORS } from "../config/config_chart";

const ChartStatProducts = (props) => {

    let database = { labels: [], data: [], label: label + " statistic in a chart" }
    for (let entry of maxVisitedOfClient) {
        arrayEntriesClients.push(entry);
        database.labels.push(entry[0]);
        database.data.push(entry[1].totalPurchases);
    }

    const data = {
        labels: props.database.labels,
        datasets: [{
            label: props.database.label,
            data: props.database.data,
            backgroundColor: [...COLORS]
        }]
    };

    return <React.Fragment>
        <div className="chart-wrapper">
            <Bar
                className="chart"
                data={data}
                width={100}
                height={50}
                options={{ maintainAspectRatio: true, }}
            />
        </div>
    </React.Fragment>
}

export default ChartStatProducts;
